function findTheDuplicateNumber(data) {
    const nums = data.split(' ').map(Number);
    for (let i = 0; i < nums.length; i++) {
        for (let j = i + 1; j < nums.length; j++) {
            if (nums[i] === nums[j]) {
                return nums[i];
            }
        }
    }
    return 0;
}

