class Solution {
    public int findTheDuplicateNumber(int[] data) {
        for (int i = 0; i < data.length; i++) {
            for (int j = i + 1; j < data.length; j++) {
                if (data[i] == data[j]) {
                    return data[i];
                }
            }
        }
        return -1; // In case there is no duplicate, though the problem guarantees one.
    }
}

