class Solution {
    public int findTheDuplicateNumber(int[] data) {
        int tortoise = data[0];
        int hare = data[0];
        // Phase 1: Finding the intersection point
        do {
            tortoise = data[tortoise];
            hare = data[data[hare]];
        }
        while (tortoise != hare);
        // Phase 2: Finding the entrance to the cycle
        tortoise = data[0];
        while (tortoise != hare) {
            tortoise = data[tortoise];
            hare = data[hare];
        }
        return hare;
    }
}

