func findTheDuplicateNumber(data []int) int {
    tortoise := data[0]
    hare := data[0]

    // Phase 1: Finding the intersection point
    for {
        tortoise = data[tortoise]
        hare = data[data[hare]]
        if tortoise == hare {
            break
        }
    }

    // Phase 2: Finding the entrance to the cycle
    tortoise = data[0]
    for tortoise != hare {
        tortoise = data[tortoise]
        hare = data[hare]
    }

    return tortoise
}

